#[derive(Debug)]
pub struct KVCache {
    pub max_seq_len: usize,
    /// Number of layers this cache holds slots for. In fluid-memory mode
    /// (single-layer trisplit workers, see `with_base`) this is 1 even when
    /// the model has 60 — the pipeline only KVs for the layer it owns.
    pub num_layers: usize,
    pub num_kv_heads: usize,
    pub head_dim: usize,
    /// Absolute index of the FIRST slot's owning layer. Callers pass
    /// absolute layer indices; the cache subtracts `base_layer` internally.
    /// `0` for full-model native runs and back-compat.
    pub base_layer: usize,
    pub keys: Vec<f32>,
    pub values: Vec<f32>,
}

impl KVCache {
    pub fn new(
        num_layers: usize,
        num_kv_heads: usize,
        head_dim: usize,
        max_seq_len: usize,
    ) -> Self {
        Self::with_base(0, num_layers, num_kv_heads, head_dim, max_seq_len)
    }

    /// Fluid-memory constructor. `base_layer` = absolute index of the first
    /// slot, `num_layers` = number of slots. A trisplit worker that owns
    /// layer 17 calls `with_base(17, 1, …)`. Calls to `save_kv(layer=17, …)`
    /// then map to local slot 0; an out-of-range layer index panics in
    /// debug builds via `local_layer`.
    pub fn with_base(
        base_layer: usize,
        num_layers: usize,
        num_kv_heads: usize,
        head_dim: usize,
        max_seq_len: usize,
    ) -> Self {
        let size = num_layers * num_kv_heads * max_seq_len * head_dim;
        KVCache {
            max_seq_len,
            num_layers,
            num_kv_heads,
            head_dim,
            base_layer,
            keys: vec![0.0; size],
            values: vec![0.0; size],
        }
    }

    /// Translate absolute layer → local slot. In fluid-memory mode the
    /// caller passes the absolute layer it owns; this returns the cache
    /// row offset for that layer's K/V buffer.
    #[inline]
    fn local_layer(&self, layer: usize) -> usize {
        debug_assert!(
            layer >= self.base_layer && layer < self.base_layer + self.num_layers,
            "kv_cache layer {} outside owned range [{}, {})",
            layer,
            self.base_layer,
            self.base_layer + self.num_layers,
        );
        layer - self.base_layer
    }

    pub fn get_key_layer_offset(&self, layer: usize) -> usize {
        self.local_layer(layer) * self.num_kv_heads * self.max_seq_len * self.head_dim
    }

    pub fn get_val_layer_offset(&self, layer: usize) -> usize {
        self.local_layer(layer) * self.num_kv_heads * self.max_seq_len * self.head_dim
    }

    /// Zero every K/V slot. Used by the early-exit bench to start each run from
    /// a clean cache so layer-skipped positions read deterministic zeros, not
    /// leftovers from a previous run.
    pub fn clear(&mut self) {
        self.keys.iter_mut().for_each(|x| *x = 0.0);
        self.values.iter_mut().for_each(|x| *x = 0.0);
    }

    pub fn save_kv(&mut self, layer: usize, pos: usize, k: &[f32], v: &[f32]) {
        let layer_offset = self.get_key_layer_offset(layer);
        for h in 0..self.num_kv_heads {
            let head_offset = layer_offset + h * self.max_seq_len * self.head_dim;
            let dest_offset = head_offset + pos * self.head_dim;
            let src_offset = h * self.head_dim;

            self.keys[dest_offset..dest_offset + self.head_dim]
                .copy_from_slice(&k[src_offset..src_offset + self.head_dim]);

            self.values[dest_offset..dest_offset + self.head_dim]
                .copy_from_slice(&v[src_offset..src_offset + self.head_dim]);
        }
    }
}
